import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String name = scanner.nextLine();

        // Dynamically allocate memory for the buffer based on user input length
        byte[] buffer = new byte[name.length()];

        // Copy the user input into the dynamically allocated buffer
        System.arraycopy(name.getBytes(), 0, buffer, 0, name.length());

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
